import React from "react";
import { useParams } from "react-router-dom";
import {
  Container,
  Typography,
  Box,
  Grid,
  Card,
  CardContent,
  CardMedia,
  CardActions,
  Button,
} from "@mui/material";

import { doctors } from "../data/doctors"; // fixed import

const DoctorsList = () => {
  const { hospitalId } = useParams(); 
  const hospitalDoctors = doctors.filter(
    (doc) => doc.hospitalId === Number(hospitalId),
  );

  return (
    <Container maxWidth="lg" sx={{ py: 6 }}>
      <Typography
        variant="h4"
        align="center"
        gutterBottom
        sx={{ color: "#1976d2" }}
      >
        Doctors at Hospital ID {hospitalId}
      </Typography>

      {hospitalDoctors.length === 0 ? (
        <Typography align="center" color="text.secondary" sx={{ mt: 4 }}>
          No doctors found for this hospital yet.
        </Typography>
      ) : (
        <Grid container spacing={4} sx={{ mt: 2 }}>
          {hospitalDoctors.map((doctor) => (
            <Grid item xs={12} sm={6} md={4} key={doctor.id}>
              <Card
                elevation={3}
                sx={{
                  height: "100%",
                  display: "flex",
                  flexDirection: "column",
                }}
              >
                <CardMedia
                  component="img"
                  height="220"
                  image={doctor.image}
                  alt={doctor.name}
                  sx={{ objectFit: "cover" }}
                />
                <CardContent sx={{ flexGrow: 1 }}>
                  <Typography variant="h6" gutterBottom>
                    {doctor.name}
                  </Typography>
                  <Typography variant="subtitle1" color="primary">
                    {doctor.specialty}
                  </Typography>
                  <Typography
                    variant="body2"
                    color="text.secondary"
                    sx={{ mt: 1 }}
                  >
                    Experience: {doctor.experience}
                  </Typography>
                  <Typography
                    variant="body2"
                    color="text.secondary"
                    sx={{ mt: 0.5 }}
                  >
                    Availability: {doctor.availability}
                  </Typography>
                </CardContent>
                <CardActions sx={{ justifyContent: "center", pb: 2 }}>
                  <Button
                    variant="contained"
                    size="small"
                    // later → link to /doctor/:id
                    onClick={() =>
                      alert(
                        `View profile of ${doctor.name} – to be implemented`,
                      )
                    }
                  >
                    View Profile
                  </Button>
                </CardActions>
              </Card>
            </Grid>
          ))}
        </Grid>
      )}
    </Container>
  );
};

export default DoctorsList;
